// ================================================
// CONTRACT RENEWAL FILTER
// Keep only contracts renewing inside the window
// Drop records missing a date or an owner
// ================================================

const body = $input.first().json;
const results = Array.isArray(body.results) ? body.results : [];

const warningWindowDays = 60; // alert when renewal is within 60 days
const now = new Date();

const kept = [];

for (const deal of results) {
  const props = deal.properties || {};
  const renewalRaw = props.renewal_date || '';
  const ownerId = props.hubspot_owner_id || '';

  // Skip records missing a renewal date or an owner
  if (!renewalRaw || !ownerId) {
    continue;
  }

  const renewalDate = new Date(renewalRaw);
  if (isNaN(renewalDate.getTime())) {
    continue;
  }

  const daysToRenewal = Math.ceil((renewalDate - now) / (1000 * 60 * 60 * 24));

  // Only keep upcoming renewals inside the warning window
  if (daysToRenewal < 0 || daysToRenewal > warningWindowDays) {
    continue;
  }

  kept.push({
    json: {
      dealId: deal.id,
      dealName: props.dealname || 'Unnamed Contract',
      amount: Number(props.amount || 0),
      ownerId,
      renewalDate: renewalDate.toISOString().split('T')[0],
      daysToRenewal,
      usageScore: Number(props.product_usage_score || 0),
      engagementScore: Number(props.engagement_score || 0),
      lastLoginDays: Number(props.last_login_days || 0),
      processedAt: new Date().toISOString()
    }
  });
}

// Sentinel so the downstream IF can route cleanly when empty
if (kept.length === 0) {
  return [{ json: { _empty: true } }];
}

return kept;

// ================================================
// RENEWAL RISK SCORER
// Builds a 0-100 risk score from usage signals
// ================================================

const item = $input.first().json;

if (item._empty) {
  return [{ json: { _empty: true } }];
}

const out = [];

for (const entry of $input.all()) {
  const d = entry.json;
  if (d._empty) { continue; }

  // Lower usage and engagement = higher risk
  const usageRisk = Math.max(0, 100 - d.usageScore);
  const engagementRisk = Math.max(0, 100 - d.engagementScore);
  const inactivityRisk = Math.min(100, d.lastLoginDays * 2);
  const urgencyRisk = d.daysToRenewal <= 30 ? 20 : 0;

  const riskScore = Math.min(100, Math.round(
    (usageRisk * 0.35) +
    (engagementRisk * 0.35) +
    (inactivityRisk * 0.2) +
    urgencyRisk
  ));

  const threshold = 50; // flag renewals scoring at or above this

  out.push({
    json: {
      ...d,
      riskScore,
      threshold,
      isAtRisk: riskScore >= threshold
    }
  });
}

if (out.length === 0) {
  return [{ json: { _empty: true } }];
}

return out;

